 1	import * as React from 'react';
 2	
 3	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Text, TextVariants } from '@patternfly/react-core';
 6	import { ExternalLinkAltIcon } from '@patternfly/react-icons';
 7	
 8	const TolerationModalDescriptionText: React.FC = () => {
 9	  const { t } = useKubevirtTranslation();
10	  return (
11	    <>
12	      <Text className="text-muted" component={TextVariants.p}>
13	        {t(
14	          'Tolerations are applied to VirtualMachines, and allow (but do not require) the VirtualMachines to schedule onto Nodes with matching taints.',
15	        )}
16	      </Text>
17	      <Text className="text-muted" component={TextVariants.p}>
18	        {t(
19	          'Add tolerations to allow a VirtualMachine to schedule onto Nodes with matching taints.',
20	        )}
21	      </Text>
22	      <Text component={TextVariants.a} href={documentationURL.TAINTS_TOLERATION} target="_blank">
23	        {t('Taints and Tolerations documentation')} <ExternalLinkAltIcon />
24	      </Text>
25	    </>
26	  );
27	};
28	export default TolerationModalDescriptionText;

